import { useState, useContext } from 'react';
import { toast } from 'react-toastify';
import { FaSeedling } from 'react-icons/fa';
import { AuthContext } from '../context/AuthContext';
import advisoryService from '../services/advisoryService';
import Spinner from './Spinner';

function AdvisoryForm({ onAdvisoryCreated }) {
  const [formData, setFormData] = useState({
    soilType: '',
    season: '',
    waterLevel: ''
  });
  const [loading, setLoading] = useState(false);
  const { user, isAuthenticated } = useContext(AuthContext);

  const { soilType, season, waterLevel } = formData;

  const onChange = (e) => {
    setFormData((prevState) => ({
      ...prevState,
      [e.target.id]: e.target.value,
    }));
  };

  const onSubmit = async (e) => {
    e.preventDefault();

    if (!isAuthenticated) {
      toast.error('Please log in to get crop recommendations');
      return;
    }

    if (!soilType || !season || !waterLevel) {
      toast.error('Please fill all fields');
      return;
    }

    setLoading(true);
    try {
      const advisory = await advisoryService.createAdvisory(formData);
      toast.success('Advisory created successfully');
      onAdvisoryCreated(advisory);
      // Reset form
      setFormData({
        soilType: '',
        season: '',
        waterLevel: ''
      });
    } catch (error) {
      const message = error.response?.data?.message || 'Something went wrong';
      toast.error(message);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <Spinner />;
  }

  return (
    <div className="bg-white p-6 rounded-lg shadow-md">
      <form onSubmit={onSubmit}>
        <div className="mb-4">
          <label htmlFor="soilType" className="block text-gray-700 font-medium mb-2">
            Soil Type
          </label>
          <select
            id="soilType"
            value={soilType}
            onChange={onChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500"
          >
            <option value="">Select Soil Type</option>
            <option value="clay">Clay Soil</option>
            <option value="sandy">Sandy Soil</option>
            <option value="loamy">Loamy Soil</option>
            <option value="silty">Silty Soil</option>
            <option value="peaty">Peaty Soil</option>
            <option value="chalky">Chalky Soil</option>
            <option value="black">Black Soil</option>
            <option value="red">Red Soil</option>
          </select>
        </div>

        <div className="mb-4">
          <label htmlFor="season" className="block text-gray-700 font-medium mb-2">
            Growing Season
          </label>
          <select
            id="season"
            value={season}
            onChange={onChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500"
          >
            <option value="">Select Season</option>
            <option value="kharif">Kharif (Monsoon)</option>
            <option value="rabi">Rabi (Winter)</option>
            <option value="zaid">Zaid (Summer)</option>
          </select>
        </div>

        <div className="mb-6">
          <label htmlFor="waterLevel" className="block text-gray-700 font-medium mb-2">
            Water Availability
          </label>
          <select
            id="waterLevel"
            value={waterLevel}
            onChange={onChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500"
          >
            <option value="">Select Water Availability</option>
            <option value="high">High (Regular irrigation or good rainfall)</option>
            <option value="medium">Medium (Moderate irrigation or rainfall)</option>
            <option value="low">Low (Limited irrigation or rainfall)</option>
          </select>
        </div>

        <button
          type="submit"
          className="w-full bg-green-600 text-white py-2 px-4 rounded-md hover:bg-green-700 flex items-center justify-center"
        >
          <FaSeedling className="mr-2" />
          Get Recommendations
        </button>
      </form>
    </div>
  );
}

export default AdvisoryForm;
